using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change: Discriminator property renamed to $type in EF Core 9.
        // Preserve the old property name so existing documents remain queryable.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change: id no longer contains the discriminator prefix in EF Core 9.
        // Preserve the old "Blog|1" format so existing documents are still found by key.
        modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

        // Breaking change: HasIndex now throws for Cosmos DB entities in EF Core 9.
        // Cosmos DB indexing is managed via the container's indexing policy, not EF Core.
        // REMOVED: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

